record.field:
if record.x_appointment_type_id:
    action = {
        "type": "ir.actions.act_window",
        "res_model": "calendar.event",
        "view_mode": "gantt",
        "view_id": env.ref("appointment.calendar_event_view_gantt_booking_resource").id,
        "context": {
            "default_appointment_type_id": record.x_appointment_type_id.id,
            "default_name": record.x_appointment_type_id.name,
            "default_x_task_id": record.id,
            "default_partner_ids" : [(6, 0, [record.partner_id.id])] if record.partner_id else [],
        },
    }

for task in records:
    if task.partner_id and task.x_vehicle_id:
        sale_order = env['sale.order'].create({
            'partner_id': task.partner_id.id,
            'x_vehicle_id': task.x_vehicle_id.id,
            'x_chassis_number': task.x_chassis_number,
            'x_task_id': task.id,
        })
        task['sale_order_id'] = sale_order.id
        action = {
            'type': 'ir.actions.act_window',
            'res_model': 'sale.order',
            'view_mode': 'form',
            'res_id': sale_order.id,
        }

for task in records:
    if task.partner_id and task.x_vehicle_id:
        invoice = env['account.move'].create({
            'move_type': 'out_invoice',
            'partner_id': task.partner_id.id,
            'x_vehicle_id': task.x_vehicle_id.id,
            'x_chassis_number': task.x_chassis_number,
            'x_task_id': task.id,
        })
        task['x_is_invoice'] = True
        action = {
            'type': 'ir.actions.act_window',
            'res_model': 'account.move',
            'view_mode': 'form',
            'res_id': invoice.id,
        }

for task in records:
    if task.x_vehicle_id and task.x_odometer:
        env['fleet.vehicle.odometer'].create({
            'value': task.x_odometer,
            'vehicle_id': task.x_vehicle_id.id,
            'driver_id': task.x_vehicle_id.driver_id.id,
        })

for task in records:
    if not task.partner_id:
        raise UserError("You must set a Customer before moving to Booking Confirm.")
    if not task.partner_id.email:
        raise UserError("You must set an Email for the Customer.")
    if not task.x_vehicle_id:
        raise UserError("You must set a Vehicle before moving to Booking Confirm.")
    if not task.x_appointment_type_id:
        raise UserError("You must set an Appointment Type before moving to Booking Confirm.")

    invite = env['appointment.invite'].search([('appointment_type_ids', 'in', [task.x_appointment_type_id.id]), ('x_task_id', '=', task.id),], limit=1)
    if not invite:
        invite = env['appointment.invite'].create({'appointment_type_ids': [(6, 0, [task.x_appointment_type_id.id])],'x_task_id': task.id})
    booking_url = invite.book_url or ''
    task.write({'x_booking_url': booking_url})
    # Send appointment booking email
    env.ref('garage_auto_repair.mail_template_task_appointment_booking').send_mail(task.id)

for event in records:
    env['appointment.invite'].search([
        ('appointment_type_ids', 'in', [event.appointment_type_id.id]),
    ], limit=1).x_task_id['state'] = '03_approved'
